    'Two critical items require attention: API migration deadline (tomorrow) and enterprise client renewal at risk. Revenue tracking ahead of Q1 target. Team velocity up 12% WoW. One operational objective behind schedule.',
    now()
  )
  RETURNING id INTO v_report_id;

  -- Risks

  -- Tasks

  -- Objectives

  -- Metrics
END $$;
